1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	const CURSED_SURCHARGE_PERCENT = 50;
4	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_PERCENT = 20;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_PRICE = 60;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const DEDUCTIBLE = 100;
32	const CAP_MULTIPLIER = 2;
33	
34	const itemBasePremium = (item: any): number => {
35	  if (!(item.type in BASE_PREMIUMS)) {
36	    throw new Error(`Unknown item type: ${item.type}`);
37	  }
38	  return BASE_PREMIUMS[item.type];
39	};
40	
41	const sumItemPremiums = (items: any[]): number =>
42	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
43	
44	const groupByType = (items: any[]): Record<string, any[]> =>
45	  items.reduce((groups, item) => {
46	    (groups[item.type] ||= []).push(item);
47	    return groups;
48	  }, {} as Record<string, any[]>);
49	
50	const isCompleteBlock = (type: string, group: any[]): boolean =>
51	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
52	
53	const groupPremium = (type: string, group: any[]): number =>
54	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
55	
56	const calculateBasePremium = (items: any[]): number =>
57	  Object.entries(groupByType(items)).reduce(
58	    (total, [type, group]) => total + groupPremium(type, group),
59	    0
60	  );
61	
62	const percentOf = (amount: number, percent: number): number =>
63	  (amount * percent) / 100;
64	
65	type Rule<T> = { applies: (target: T) => boolean; percent: number };
66	
67	const ITEM_SURCHARGE_RULES: Rule<any>[] = [
68	  { applies: (item) => item.cursed, percent: CURSED_SURCHARGE_PERCENT },
69	  {
70	    applies: (item) => item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
71	    percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
72	  },
73	];
74	
75	const FOLLOW_UP_DISCOUNT_PERCENT = 15;
76	
77	type PolicyContext = { customer: any; isFollowUp: boolean };
78	
79	const POLICY_MODIFIER_RULES: Rule<PolicyContext>[] = [
80	  { applies: () => true, percent: FIRST_INSURANCE_SURCHARGE_PERCENT },
81	  {
82	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
83	    percent: -LOYALTY_DISCOUNT_PERCENT,
84	  },
85	  {
86	    applies: ({ isFollowUp }) => isFollowUp,
87	    percent: -FOLLOW_UP_DISCOUNT_PERCENT,
88	  },
89	];
90	
91	const sumRulePercentages = <T>(rules: Rule<T>[], target: T, base: number): number =>
92	  rules.reduce(
93	    (sum, rule) => sum + (rule.applies(target) ? percentOf(base, rule.percent) : 0),
94	    0
95	  );
96	
97	const itemSurcharge = (item: any): number =>
98	  sumRulePercentages(ITEM_SURCHARGE_RULES, item, itemBasePremium(item));
99	
100	const calculateItemSurcharges = (items: any[]): number =>
101	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
102	
103	const calculatePolicyModifiers = (context: PolicyContext, policyBase: number): number =>
104	  sumRulePercentages(POLICY_MODIFIER_RULES, context, policyBase);
105	
106	const quotePremium = (items: any[], context: PolicyContext): number => {
107	  const policyBase = calculateBasePremium(items);
108	  const itemSurcharges = calculateItemSurcharges(items);
109	  const policyModifiers = calculatePolicyModifiers(context, policyBase);
110	  return Math.ceil(policyBase + policyModifiers + itemSurcharges + PROCESSING_FEE);
111	};
112	
113	const itemInsuranceValue = (item: any): number => INSURANCE_VALUES[item.type];
114	
115	const calculateInsuranceSum = (items: any[]): number =>
116	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
117	
118	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
119	const HIGH_ENCHANTMENT_DAMAGE_MULTIPLIER = 0.5;
120	const DEFAULT_DAMAGE_MULTIPLIER = 1;
121	
122	const isHighEnchantmentForClaim = (item: any): boolean =>
123	  !!item && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
124	
125	const damageMultiplier = (item: any): number =>
126	  isHighEnchantmentForClaim(item)
127	    ? HIGH_ENCHANTMENT_DAMAGE_MULTIPLIER
128	    : DEFAULT_DAMAGE_MULTIPLIER;
129	
130	const calculateDamagePayout = (damage: any, items: any[]): number => {
131	  if (damage.amount < 0) {
132	    throw new Error(`Negative damage amount: ${damage.amount}`);
133	  }
134	  const item = items.find((i) => i.type === damage.itemType);
135	  if (!item) {
136	    throw new Error(`Claim item type not in policy: ${damage.itemType}`);
137	  }
138	  return Math.max(0, Math.floor(damage.amount * damageMultiplier(item) - DEDUCTIBLE));
139	};
140	
141	const sumDamagePayouts = (damages: any[], items: any[]): number =>
142	  damages.reduce((sum, damage) => sum + calculateDamagePayout(damage, items), 0);
143	
144	type Policy = { remainingCap: number; items: any[] };
145	
146	const countBy = <T>(items: T[], key: (item: T) => string): Record<string, number> =>
147	  items.reduce((counts, item) => {
148	    const k = key(item);
149	    counts[k] = (counts[k] || 0) + 1;
150	    return counts;
151	  }, {} as Record<string, number>);
152	
153	const processClaim = (step: any, policies: Policy[]) => {
154	  const policy = policies[step.policy];
155	  const damageCounts = countBy(step.incident.damages, (d: any) => d.itemType);
156	  const itemCounts = countBy(policy.items, (i: any) => i.type);
157	  for (const [itemType, count] of Object.entries(damageCounts)) {
158	    if (count > (itemCounts[itemType] || 0)) {
159	      throw new Error(`Too many damage entries for item type: ${itemType}`);
160	    }
161	  }
162	  const payout = Math.min(sumDamagePayouts(step.incident.damages, policy.items), policy.remainingCap);
163	  policy.remainingCap -= payout;
164	  return { payout, remainingCap: policy.remainingCap };
165	};
166	
167	const processQuote = (step: any, index: number, customer: any, policies: Policy[]) => {
168	  const premium = quotePremium(step.items, { customer, isFollowUp: index > 0 });
169	  const insuranceSum = calculateInsuranceSum(step.items);
170	  policies.push({ remainingCap: CAP_MULTIPLIER * insuranceSum, items: step.items });
171	  return { premium };
172	};
173	
174	const processStep = (step: any, index: number, customer: any, policies: Policy[]) =>
175	  step.op === "claim"
176	    ? processClaim(step, policies)
177	    : processQuote(step, index, customer, policies);
178	
179	export const runScenario = (scenario: any): unknown => {
180	  const policies: Policy[] = [];
181	  return {
182	    results: scenario.steps.map((step: any, index: number) =>
183	      processStep(step, index, scenario.customer, policies)
184	    ),
185	  };
186	};
